    map['@type'] = type;
    if (id != null) map['@id'] = id;
    return map;
  }

  factory Time.fromJson(Map<String, dynamic> json) {
    final obj = Time();
    if (json is Map && json['@id'] != null) obj.id = json['@id'] as String?;
    return obj;
  }
}

