SchemaOrgEntity schemaOrgFromString(String jsonString) {
  final data = json.decode(jsonString);
  if (data is Map<String, dynamic>) {
    SchemaValidator.validate(data);
    final type = data['@type'];
    switch (type) {
      case '3DModel': return Schema3DModel.fromJson(data);
      case 'AMRadioChannel': return AMRadioChannel.fromJson(data);
      case 'APIReference': return APIReference.fromJson(data);
      case 'AboutPage': return AboutPage.fromJson(data);
      case 'AcceptAction': return AcceptAction.fromJson(data);
      case 'Accommodation': return Accommodation.fromJson(data);
      case 'AccountingService': return AccountingService.fromJson(data);
      case 'AchieveAction': return AchieveAction.fromJson(data);
      case 'Action': return Action.fromJson(data);
      case 'ActionAccessSpecification': return ActionAccessSpecification.fromJson(data);
      case 'ActionStatusType': return ActionStatusType.fromJson(data);
      case 'ActivateAction': return ActivateAction.fromJson(data);
      case 'AddAction': return AddAction.fromJson(data);
      case 'AdministrativeArea': return AdministrativeArea.fromJson(data);
      case 'AdultEntertainment': return AdultEntertainment.fromJson(data);
      case 'AdvertiserContentArticle': return AdvertiserContentArticle.fromJson(data);
      case 'AggregateOffer': return AggregateOffer.fromJson(data);
      case 'AggregateRating': return AggregateRating.fromJson(data);
      case 'AgreeAction': return AgreeAction.fromJson(data);
      case 'Airline': return Airline.fromJson(data);
      case 'Airport': return Airport.fromJson(data);
